#include <stdio.h>
#include <inttypes.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t N; scanf("%" PRId64, &N);
        int64_t ans = N * (N - 1);
        printf("%" PRId64 "\n", ans);
    }
    return 0;
}

